import{_ as t,c as o,o as s,ag as n}from"./chunks/framework.DVUBUV_u.js";const c=JSON.parse('{"title":"Избранное","description":"","frontmatter":{"title":"Избранное"},"headers":[],"relativePath":"store/favorite.md","filePath":"store/favorite.md"}'),a={name:"store/favorite.md"};function e(i,r,g,l,h,p){return s(),o("div",null,[...r[0]||(r[0]=[n('<h1 id="избранное-pinia-store" tabindex="-1">Избранное (Pinia Store) <a class="header-anchor" href="#избранное-pinia-store" aria-label="Permalink to &quot;Избранное (Pinia Store)&quot;">​</a></h1><p><strong>Избранные сторы</strong> — это сохранённый список <strong>имён Pinia‑сторов</strong>, по которым удобно ориентироваться во вкладке <strong>Stores</strong>: отмеченные строки поднимаются <strong>выше</strong> остальных, у них горит <strong>звезда</strong>, в шапке показывается, сколько избранных сторов найдено среди текущего списка.</p><p>Общее описание вкладки Store: <a href="/docs/store/general.html">Основные возможности</a>.<br> Избранное <strong>компонентов Vue</strong> (вкладка Props) — отдельный механизм: <a href="/docs/props/favorite.html">Избранное (Props)</a>.</p><hr><h2 id="где-добавить-и-убрать" tabindex="-1">Где добавить и убрать <a class="header-anchor" href="#где-добавить-и-убрать" aria-label="Permalink to &quot;Где добавить и убрать&quot;">​</a></h2><ul><li><strong>В таблице Stores</strong> — клик по <strong>звезде</strong> у строки добавляет или удаляет избранное для <strong>отображаемого имени стора</strong> (то имя, которое вы видите в колонке Name), вместе с сохранением внутреннего идентификатора стора в текущей сессии, если он доступен.</li><li><strong>В карточке стора</strong> — кнопка с той же логикой («добавить в избранное» / «убрать из избранного»).</li><li><strong>В Options</strong> — секция <strong>Favorite Stores</strong> в блоке настроек <strong>Pinia</strong>: можно <strong>ввести имя вручную</strong>, удалить запись, открыть элемент для <strong>редактирования</strong> имени в боковой панели.</li></ul><p>Настройки сохраняются в общем хранилище инспектора вместе с остальными параметрами.</p><hr><h2 id="точное-имя-и-маски" tabindex="-1">Точное имя и маски <a class="header-anchor" href="#точное-имя-и-маски" aria-label="Permalink to &quot;Точное имя и маски&quot;">​</a></h2><p>В списке избранного каждая строка задаёт <strong>шаблон имени стора</strong>:</p><ul><li>Если в шаблоне <strong>нет</strong> символа <strong><code>*</code></strong>, совпадение <strong>строгое</strong>: звезда горит только у стора с <strong>таким же</strong> именем, как в записи.</li><li>Символ <strong><code>*</code></strong> в шаблоне означает <strong>произвольный фрагмент</strong> (как подстановка в маске): например шаблон вида <strong>use*Store</strong> может подсветить и <strong>useUserStore</strong>, и <strong>useAuthStore</strong>, если их отображаемые имена подходят под маску.</li></ul><p>При снятии избранного со строки таблицы удаляются <strong>все</strong> записи из списка настроек, которые считаются совпадающими: и точное имя, и подходящие по маске — чтобы звезда погасла полностью.</p><p>Ручной ввод в Options явно подсказывает поддержку <strong>wildcard</strong> в поле имени.</p><hr><h2 id="сортировка-и-счетчик" tabindex="-1">Сортировка и счётчик <a class="header-anchor" href="#сортировка-и-счетчик" aria-label="Permalink to &quot;Сортировка и счётчик&quot;">​</a></h2><p>Таблица <strong>Stores</strong> после обновления списка <strong>упорядочивает</strong> строки так, что избранные оказываются <strong>раньше</strong> неизбранных (порядок внутри каждой группы может зависеть от исходного ответа со страницы).</p><p>В шапке отображается бейдж <strong>«найдено / всего»</strong> избранных: сколько отмеченных сторов видно с учётом <strong>поиска</strong> и сколько записей в списке избранного в настройках. Клик по бейджу ведёт в <strong>Options</strong> на секцию избранных сторов (<strong>pinia-favorites-section</strong>), чтобы править список без поиска по вкладке.</p><hr><h2 id="редактирование-в-options" tabindex="-1">Редактирование в Options <a class="header-anchor" href="#редактирование-в-options" aria-label="Permalink to &quot;Редактирование в Options&quot;">​</a></h2><p>При выборе записи избранного в таблице настроек можно открыть <strong>редактирование</strong> имени в деталях: после сохранения обновляются поля <strong>идентификатора</strong> и <strong>отображаемого имени</strong> записи (они приводятся к одному новому значению). Имеет смысл не оставлять пустое имя.</p><hr><h2 id="практические-советы" tabindex="-1">Практические советы <a class="header-anchor" href="#практические-советы" aria-label="Permalink to &quot;Практические советы&quot;">​</a></h2><ul><li>Для одного проекта заведите избранное под <strong>ключевые</strong> сторы: пользователь, корзина, настройки — чтобы не листать длинный список после каждого обновления.</li><li><strong>Маски</strong> удобны, если в проекте много однотипно названных сторов; слишком широкая маска может пометить звёздами лишние строки.</li><li>Избранное <strong>не меняет</strong> работу Pinia в приложении и не синхронизируется между разными браузерами или машинами автоматически — это локальные настройки инспектора.</li></ul><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/store/general.html">Основные возможности Store</a></li><li><a href="/docs/props/favorite.html">Избранное (Props)</a></li><li><a href="/docs/options/customize.html">Персонализация / настройки</a></li></ul>',26)])])}const u=t(a,[["render",e]]);export{c as __pageData,u as default};
